// Best-effort: from the antecedent we derive r1.id@ == r2.id@ via
    // r1@ == r2@ == AbstractEndPoint{id: arg@}.  However the goal is
    // r1.id == r2.id where id: Vec<u8>.  In this Verus version, Vec is
    // declared with #[verifier::external_type_specification] and
    // #[verifier::external_body], and its view() is `uninterp`.  No
    // axiom states that view is injective and Vec is not Structural,
    // so x == y is NOT derivable from x@ == y@ for two Vec<u8>.
    // The available lemmas (lemma_vec_obeys_view_eq /
    // lemma_vec_obeys_deep_eq) only relate eq_spec to view equality,
    // not the spec-level `==`.  This obligation is unprovable without
    // an axiom that we are forbidden to introduce.
    if r1@ == parse_arg_as_end_point(arg@) && r2@ == parse_arg_as_end_point(arg@) {
        assert(r1.id@ == arg@);
        assert(r2.id@ == arg@);
        assert(r1.id@ =~= r2.id@);
        assert(r1.id@ == r2.id@);
    }

